const b = $json.body || {};
const event = b.event;
let content;
if (event === 'signup') {
  content = `🎉 **New signup!** — that's **${b.total}** total.`;
} else if (event === 'milestone') {
  const n = Number(b.number);
  const map = {
    100: '💯 **100 Founders!** A hundred people have claimed a Founding 500 spot.',
    250: '🔥 **250 Founders!** Halfway to the cap.',
    400: '⚡ **400 Founders!** Only 100 Founding 500 spots left.',
    500: '🏁 **FOUNDING 500 SOLD OUT** — all 500 lifetime spots are claimed. 🎉',
  };
  content = map[n] || `🏆 **Founding ${n}!**`;
} else {
  return [];
}
return [{ json: { content } }];
